async function writeScaffoldScenario(projectPath: string, scaffold: IGameScaffoldDefinition, playerId: string): Promise<string> {
  const absolutePath = resolve(projectPath, scaffold.scenario.path);
  await mkdir(resolve(absolutePath, ".."), { recursive: true });
  const scenario = {
    artifacts: {
      console: true,
      network: true,
      runtimeTrace: true,
      screenshots: "before-after",
    },
    assert: {
      diagnostics: {
        noConsoleErrors: true,
        noNetworkErrors: true,
        noRuntimeDiagnostics: true,
        runtimeReady: true,
      },
      movement: {
        axis: scaffold.scenario.axis,
        entity: playerId,
        minDistance: 0.05,
        minVelocity: 0.001,
      },
    },
    name: scaffold.scenario.name,
    schemaVersion: 1,
    steps: [
      {
        holdFrames: 30,
        label: "prove-input-movement",
        press: scaffold.scenario.press,
        release: true,
      },
    ],
    subject: playerId,
    target: "web",
    viewport: {
      height: 720,
      width: 1280,
    },
    warmupFrames: 5,
  };
  await writeFile(absolutePath, `${JSON.stringify(scenario, null, 2)}\n`, "utf8");
  return scaffold.scenario.path;
}

function stringValue(value: unknown): string | undefined {
  return typeof value === "string" && value.trim() !== "" ? value : undefined;
}

async function writeScaffoldEvidence(projectPath: string, evidence: { archetype: GameArchetypeId; filesWritten: string[]; planArtifactPath: string; recipeId: string; scenarioPath: string }): Promise<string> {
  const relativePath = "artifacts/game-production/scaffold-first.json";
  const absolutePath = resolve(projectPath, relativePath);
  await mkdir(resolve(absolutePath, ".."), { recursive: true });
  await writeFile(
    absolutePath,
    `${JSON.stringify(
      {
        archetype: evidence.archetype,
        filesWritten: evidence.filesWritten,
        iterateCommand: `tn iterate --project . --scenario ${evidence.scenarioPath} --json`,
        planArtifactPath: evidence.planArtifactPath,
        proofCommand: `tn playtest --project . --scenario ${evidence.scenarioPath} --stable-artifacts --json`,
        recipeId: evidence.recipeId,
        scenarioPaths: [evidence.scenarioPath],
        schema: "threenative.game-scaffold-first",
        version: "0.1.0",
      },
      null,
      2,
    )}\n`,
    "utf8",
  );
  return relativePath;
}

function compactGamePlanForStdout(plan: IGamePlan, planArtifactPath: string): Record<string, unknown> {
  return {
    archetype: plan.archetype,
    code: plan.code,
    diagnostics: plan.diagnostics,
    fileMap: {
      scripts: plan.scriptPlan.map((script) => ({ exportName: script.exportName, module: script.module, responsibility: script.responsibility })),
      source: plan.sourcePlan.map((source) => ({ document: source.document, path: source.path })),
    },
    goal: plan.goal,
    kitCandidates: plan.kitCandidates.slice(0, 3).map((kit) => ({ kitId: kit.kitId, recipeId: kit.recipeId, toolingOnly: kit.toolingOnly })),
    mechanicDecomposition: plan.mechanicDecomposition,
    message: "Full game plan written to artifacts/game-production/plan.json.",
    milestones: plan.phases.map((phase) => ({ id: phase.id, order: phase.order, summary: phase.summary })),
    mutate: plan.mutate,
    planArtifactPath,
    proofCommands: plan.proofCommands,
    recipeIds: plan.recipeIds,
    schema: "threenative.game-plan-summary",
    version: "0.1.0",
  };
}

